/** Type checker for Typed Jam (Assignment 5).
  * Implements ASTVisitor<JamType> to walk the AST and verify types.
  * Throws TypeException on a type error.
  */

import java.util.HashMap;

/** Exception thrown when a type error is detected. */
class TypeException extends RuntimeException {
  TypeException(String msg) { super(msg); }
}

/** Type checker that verifies a Typed Jam program is well-typed.
  * The type environment maps Variable objects to their declared JamType.
  * Polymorphic primitives (cons, first, rest, empty?, cons?, ref, !, =, !=, <-)
  * are handled by matching their schematic types against concrete argument types.
  */
class TypeChecker implements ASTVisitor<JamType> {

  /** The type environment mapping variables to their types. */
  private HashMap<Variable, JamType> typeEnv;

  /** Constructs a TypeChecker with an empty type environment. */
  TypeChecker() { typeEnv = new HashMap<Variable, JamType>(); }

  /** Constructs a TypeChecker with the given type environment. */
  private TypeChecker(HashMap<Variable, JamType> env) { typeEnv = env; }

  /** Returns a new TypeChecker extending the current environment with the given bindings. */
  private TypeChecker extend(Variable[] vars, JamType[] types) {
    HashMap<Variable, JamType> newEnv = new HashMap<Variable, JamType>(typeEnv);
    for (int i = 0; i < vars.length; i++) {
      newEnv.put(vars[i], types[i]);
    }
    return new TypeChecker(newEnv);
  }

  /* ===== ASTVisitor methods ===== */

  /** Integer constants have type int. */
  public JamType forIntConstant(IntConstant i) { return IntType.ONLY; }

  /** Boolean constants have type bool. */
  public JamType forBoolConstant(BoolConstant b) { return BoolType.ONLY; }

  /** Plain empty constant without type annotation is a type error in Typed Jam. */
  public JamType forEmptyConstant(EmptyConstant n) {
    throw new TypeException("empty requires a type annotation: write 'empty : T'");
  }

  /** Typed empty constant 'empty : T' has type list T. */
  @Override
  public JamType forTypedEmptyConstant(TypedEmptyConstant n) {
    return new ListType(n.elemType());
  }

  /** Variable lookup: retrieve declared type from environment. */
  public JamType forVariable(Variable v) {
    JamType t = typeEnv.get(v);
    if (t == null) throw new TypeException("Unbound variable: " + v);
    return t;
  }

  /** Standalone PrimFun is a type error; prims must be applied. */
  public JamType forPrimFun(PrimFun f) {
    throw new TypeException("Primitive function '" + f + "' used as a value; must be applied");
  }

  /** Unary operator application: type-check the argument, then check the operator. */
  public JamType forUnOpApp(UnOpApp u) {
    JamType argType = u.arg().accept(this);
    return u.rator().accept(new UnOpTypeChecker(argType));
  }

  /** Binary operator application: type-check both arguments, then check the operator. */
  public JamType forBinOpApp(BinOpApp b) {
    return b.rator().accept(new BinOpTypeChecker(b.arg1(), b.arg2()));
  }

  /** Function application: distinguish polymorphic PrimFun applications from regular ones. */
  public JamType forApp(App a) {
    AST rator = a.rator();
    AST[] args = a.args();

    /* Polymorphic primitive functions require special handling */
    if (rator instanceof PrimFun) {
      return ((PrimFun) rator).accept(new PrimFunTypeChecker(args));
    }

    /* Regular function application */
    JamType ratorType = rator.accept(this);
    if (!(ratorType instanceof FunType)) {
      throw new TypeException("Application of non-function type " + ratorType + " in: " + a);
    }
    FunType funType = (FunType) ratorType;
    JamType[] paramTypes = funType.params();
    if (args.length != paramTypes.length) {
      throw new TypeException("Function applied to wrong number of arguments: expected " +
          paramTypes.length + " but got " + args.length);
    }
    for (int i = 0; i < args.length; i++) {
      JamType argType = args[i].accept(this);
      if (!argType.equals(paramTypes[i])) {
        throw new TypeException("Argument " + i + " type mismatch: expected " +
            paramTypes[i] + " but got " + argType);
      }
    }
    return funType.result();
  }

  /** Map (lambda): type-check body in extended environment, return function type. */
  public JamType forMap(Map m) {
    Variable[] vars = m.vars();
    JamType[] types = m.types();
    if (types == null || types.length != vars.length) {
      throw new TypeException("Map is missing type annotations for parameters");
    }
    TypeChecker newChecker = extend(vars, types);
    JamType bodyType = m.body().accept(newChecker);
    return new FunType(types, bodyType);
  }

  /** If expression: condition must be bool, branches must have equal types. */
  public JamType forIf(If i) {
    JamType testType = i.test().accept(this);
    if (!testType.equals(BoolType.ONLY)) {
      throw new TypeException("If condition must have type bool, but got: " + testType);
    }
    JamType conseqType = i.conseq().accept(this);
    JamType altType = i.alt().accept(this);
    if (!conseqType.equals(altType)) {
      throw new TypeException("If branches have different types: then=" + conseqType + ", else=" + altType);
    }
    return conseqType;
  }

  /** Let expression with recursive semantics: extend environment with declared types, then check rhs. */
  public JamType forLet(Let l) {
    Def[] defs = l.defs();
    int n = defs.length;
    Variable[] vars = new Variable[n];
    JamType[] types = new JamType[n];
    for (int i = 0; i < n; i++) {
      vars[i] = defs[i].lhs();
      types[i] = defs[i].type();
      if (types[i] == null) throw new TypeException("Missing type annotation for: " + vars[i]);
    }
    /* Extend environment with all let variables (supports mutual/self recursion). */
    TypeChecker newChecker = extend(vars, types);
    /* Verify each rhs has the declared type. */
    for (int i = 0; i < n; i++) {
      JamType rhsType = defs[i].rhs().accept(newChecker);
      if (!rhsType.equals(types[i])) {
        throw new TypeException("Type mismatch for definition of " + vars[i] +
            ": declared " + types[i] + " but found " + rhsType);
      }
    }
    return l.body().accept(newChecker);
  }

  /** Block: type-check all expressions; return type of the last expression. */
  public JamType forBlock(Block b) {
    AST[] exps = b.exps();
    JamType result = null;
    for (AST exp : exps) {
      result = exp.accept(this);
    }
    return result;
  }

  /* ===== Inner type-checking visitor classes ===== */

  /** Type-checks unary operator applications. The argument has already been evaluated to a type. */
  class UnOpTypeChecker implements UnOpVisitor<JamType> {
    private JamType argType;
    UnOpTypeChecker(JamType t) { argType = t; }

    /** Unary + requires int argument, returns int. */
    public JamType forUnOpPlus() {
      if (!argType.equals(IntType.ONLY))
        throw new TypeException("Unary '+' requires int, got: " + argType);
      return IntType.ONLY;
    }

    /** Unary - requires int argument, returns int. */
    public JamType forUnOpMinus() {
      if (!argType.equals(IntType.ONLY))
        throw new TypeException("Unary '-' requires int, got: " + argType);
      return IntType.ONLY;
    }

    /** ~ requires bool argument, returns bool. */
    public JamType forOpTilde() {
      if (!argType.equals(BoolType.ONLY))
        throw new TypeException("'~' requires bool, got: " + argType);
      return BoolType.ONLY;
    }

    /** ! (dereference): requires ref 'a argument, returns 'a. */
    public JamType forOpBang() {
      if (!(argType instanceof RefType))
        throw new TypeException("'!' requires a ref type, got: " + argType);
      return ((RefType) argType).elem();
    }

    /** ref: creates a reference of type ref 'a from argument of type 'a. */
    public JamType forOpRef() {
      return new RefType(argType);
    }
  }

  /** Type-checks binary operator applications. Arguments are unevaluated ASTs. */
  class BinOpTypeChecker implements BinOpVisitor<JamType> {
    private AST arg1, arg2;
    BinOpTypeChecker(AST a1, AST a2) { arg1 = a1; arg2 = a2; }

    private JamType tc(AST a) { return a.accept(TypeChecker.this); }

    private JamType expectInt(AST a, String op) {
      JamType t = tc(a);
      if (!t.equals(IntType.ONLY))
        throw new TypeException("'" + op + "' requires int, got: " + t);
      return IntType.ONLY;
    }

    private JamType expectBool(AST a, String op) {
      JamType t = tc(a);
      if (!t.equals(BoolType.ONLY))
        throw new TypeException("'" + op + "' requires bool, got: " + t);
      return BoolType.ONLY;
    }

    public JamType forBinOpPlus() { expectInt(arg1, "+"); expectInt(arg2, "+"); return IntType.ONLY; }
    public JamType forBinOpMinus() { expectInt(arg1, "-"); expectInt(arg2, "-"); return IntType.ONLY; }
    public JamType forOpTimes() { expectInt(arg1, "*"); expectInt(arg2, "*"); return IntType.ONLY; }
    public JamType forOpDivide() { expectInt(arg1, "/"); expectInt(arg2, "/"); return IntType.ONLY; }
    public JamType forOpLessThan() { expectInt(arg1, "<"); expectInt(arg2, "<"); return BoolType.ONLY; }
    public JamType forOpGreaterThan() { expectInt(arg1, ">"); expectInt(arg2, ">"); return BoolType.ONLY; }
    public JamType forOpLessThanEquals() { expectInt(arg1, "<="); expectInt(arg2, "<="); return BoolType.ONLY; }
    public JamType forOpGreaterThanEquals() { expectInt(arg1, ">="); expectInt(arg2, ">="); return BoolType.ONLY; }
    public JamType forOpAnd() { expectBool(arg1, "&"); expectBool(arg2, "&"); return BoolType.ONLY; }
    public JamType forOpOr() { expectBool(arg1, "|"); expectBool(arg2, "|"); return BoolType.ONLY; }

    /** =: 'a, 'a -> bool (polymorphic equality). */
    public JamType forOpEquals() {
      JamType t1 = tc(arg1);
      JamType t2 = tc(arg2);
      if (!t1.equals(t2))
        throw new TypeException("'=' requires equal types, got: " + t1 + " and " + t2);
      return BoolType.ONLY;
    }

    /** !=: 'a, 'a -> bool (polymorphic inequality). */
    public JamType forOpNotEquals() {
      JamType t1 = tc(arg1);
      JamType t2 = tc(arg2);
      if (!t1.equals(t2))
        throw new TypeException("'!=' requires equal types, got: " + t1 + " and " + t2);
      return BoolType.ONLY;
    }

    /** <-: ref 'a, 'a -> unit (assignment). */
    public JamType forOpGets() {
      JamType t1 = tc(arg1);
      if (!(t1 instanceof RefType))
        throw new TypeException("'<-' first arg must be ref type, got: " + t1);
      JamType elemType = ((RefType) t1).elem();
      JamType t2 = tc(arg2);
      if (!elemType.equals(t2))
        throw new TypeException("'<-' type mismatch: ref " + elemType + " vs " + t2);
      return UnitType.ONLY;
    }
  }

  /** Type-checks primitive function applications.
    * Handles polymorphic primitives: cons, first, rest, empty?, cons?.
    */
  class PrimFunTypeChecker implements PrimFunVisitor<JamType> {
    private AST[] args;
    PrimFunTypeChecker(AST[] args) { this.args = args; }

    private JamType tc(AST a) { return a.accept(TypeChecker.this); }

    private void checkArity(String name, int expected) {
      if (args.length != expected)
        throw new TypeException("'" + name + "' requires " + expected + " argument(s), got " + args.length);
    }

    /** cons: 'a, list 'a -> list 'a */
    public JamType forConsPrim() {
      checkArity("cons", 2);
      JamType t1 = tc(args[0]);
      JamType t2 = tc(args[1]);
      if (!(t2 instanceof ListType))
        throw new TypeException("cons: second argument must be a list type, got: " + t2);
      ListType lt = (ListType) t2;
      if (!t1.equals(lt.elem()))
        throw new TypeException("cons: element type mismatch: " + t1 + " vs list " + lt.elem());
      return new ListType(t1);
    }

    /** first: list 'a -> 'a */
    public JamType forFirstPrim() {
      checkArity("first", 1);
      JamType t = tc(args[0]);
      if (!(t instanceof ListType))
        throw new TypeException("first: argument must be a list type, got: " + t);
      return ((ListType) t).elem();
    }

    /** rest: list 'a -> list 'a */
    public JamType forRestPrim() {
      checkArity("rest", 1);
      JamType t = tc(args[0]);
      if (!(t instanceof ListType))
        throw new TypeException("rest: argument must be a list type, got: " + t);
      return t;
    }

    /** empty?: list 'a -> bool */
    public JamType forEmptyPPrim() {
      checkArity("empty?", 1);
      JamType t = tc(args[0]);
      if (!(t instanceof ListType))
        throw new TypeException("empty?: argument must be a list type, got: " + t);
      return BoolType.ONLY;
    }

    /** cons?: list 'a -> bool */
    public JamType forConsPPrim() {
      checkArity("cons?", 1);
      JamType t = tc(args[0]);
      if (!(t instanceof ListType))
        throw new TypeException("cons?: argument must be a list type, got: " + t);
      return BoolType.ONLY;
    }

    /* Removed primitives: */
    public JamType forFunctionPPrim() { throw new TypeException("function? is not in Typed Jam"); }
    public JamType forNumberPPrim()   { throw new TypeException("number? is not in Typed Jam"); }
    public JamType forListPPrim()     { throw new TypeException("list? is not in Typed Jam"); }
    public JamType forRefPPrim()      { throw new TypeException("ref? is not in Typed Jam"); }
    public JamType forArityPrim()     { throw new TypeException("arity is not in Typed Jam"); }
  }
}

/** Interpreter for Typed Jam (Assignment 5).
  * Supports two evaluation modes:
  *   eagerEval()  - call-by-value binding, eager cons (value/value)
  *   lazyEval()   - call-by-value binding, lazy/need cons (value/need)
  *
  * The interpreter first parses, then checks context-sensitive syntax,
  * then type-checks, and finally evaluates.
  */

import java.io.IOException;
import java.io.Reader;


/** The exception class for Jam run-time errors during program evaluation. */
class EvalException extends RuntimeException {
  EvalException(String msg) { super(msg); }
}

/** Interpreter class supporting two forms of evaluation for Typed Jam programs:
  * call-by-value/eager (eagerEval) and call-by-value/lazy-need (lazyEval). */
class Interpreter {
  /** Parser to use. */
  Parser parser;

  /** Parsed and type-checked AST. */
  AST prog;

  Interpreter(String fileName) throws IOException {
    parser = new Parser(fileName);
    prog = checkTypes(parser.parseAndCheck());
  }

  Interpreter(Parser p) {
    parser = p;
    prog = checkTypes(parser.parseAndCheck());
  }

  Interpreter(Reader reader) {
    parser = new Parser(reader);
    prog = checkTypes(parser.parseAndCheck());
  }

  /* Interpreter API */

  /** Type-checks the given AST and returns it if well-typed; throws TypeException otherwise. */
  public AST checkTypes(AST ast) {
    ast.accept(new TypeChecker());
    return ast;
  }

  /** Evaluates using call-by-value binding and eager cons evaluation. */
  public JamVal eagerEval() { return prog.accept(valueValueVisitor); }

  /** Evaluates using call-by-value binding and call-by-need cons evaluation. */
  public JamVal lazyEval() { return prog.accept(valueNeedVisitor); }


  /* Interfaces that support different forms of variable binding and different forms of list construction */

  /** The interface supported by various binding evaluation policies: call-by-value, call-by-name, and call-by-need. */
  interface BindingPolicy {
    /** Constructs the appropriate binding object for this, binding var to ast in the evaluator ev. */
    Binding newBinding(Variable var, AST ast, EvalVisitor ev);

    /** Constructs the appropriate dummy binding object for this. */
    Binding newDummyBinding(Variable var);
  }

  /** Interface containing a factory to build the cons object specified by this ConsPolicy. */
  interface ConsPolicy {
    /** Constructs the appropriate cons given the arguments and corresponding EvalVisitor. */
    JamVal evalCons(AST[] args, EvalVisitor ev);
  }

  /* Note: Binding is defined in the file ValuesTokens because the JamClosure class depends on it. */

  /** Class representing a binding in CBV evaluation. */
  static class ValueBinding extends Binding {
    ValueBinding(Variable v, JamVal jv) { super(v, jv); }
    public JamVal value() {
      if (value == null) illegalForwardReference(var());
      return value;
    }
    public void setBinding(Suspension s) { value = s.eval(); }  // immediate evaluation
    public String toString() { return "[" + var + ", " + value + "]"; }
  }

  /** Class representing a binding in CBName evaluation. The inherited value field is ignored. */
  static class NameBinding extends Binding {
    protected Suspension susp;
    NameBinding(Variable v, Suspension s) {
      super(v, null);
      susp = s;
    }
    public JamVal value() { return (susp == null) ? illegalForwardReference(var()) : susp.eval(); }
    public void setBinding(Suspension s) { susp = s; }
    public String toString() { return "[" + var + ", " + susp + "]"; }
  }

  /** Class representing a binding in CBNeed evaluation. The inherited value field is used to hold the value
    * first computed by need. */
  static class NeedBinding extends NameBinding {
    NeedBinding(Variable v, Suspension s) { super(v, s); }
    public JamVal value() {
      if (value == null) {
        if (susp == null) illegalForwardReference(var());
        else {
          value = susp.eval();
          susp = null;  // release susp object for GC
        }
      }
      return value;
    }
    public void setBinding(AST exp, EvalVisitor ev) { susp = new ConcreteSuspension(exp, ev); value = null; }
    public String toString() { return "[" + var + ", " + value + ", " + susp + "]"; }
  }

  /** Helper method supporting Binding classes */
  static JamVal illegalForwardReference(Variable v) {
    throw new EvalException("Attempt to evaluate variable " + v + " bound to null, indicating an illegal forward reference");
  }

  /** Binding policy for call-by-value. */
  static final BindingPolicy CALL_BY_VALUE = new BindingPolicy() {
    public Binding newBinding(Variable var, AST arg, EvalVisitor ev) { return new ValueBinding(var, arg.accept(ev)); }
    public Binding newDummyBinding(Variable var) { return new ValueBinding(var, null); }
  };

  /** Binding policy for call-by-need. */
  static final BindingPolicy CALL_BY_NEED = new BindingPolicy() {
    public Binding newBinding(Variable var, AST arg, EvalVisitor ev) {
      return new NeedBinding(var, new ConcreteSuspension(arg, ev));
    }
    public Binding newDummyBinding(Variable var) { return new NeedBinding(var, null); }
  };


  /** A class representing an unevaluated expression (together with the corresponding evaluator). */
  static class ConcreteSuspension implements Suspension {
    private AST exp;
    private EvalVisitor ev;

    ConcreteSuspension(AST a, EvalVisitor e) { exp = a; ev = e; }

    AST exp() { return exp; }
    EvalVisitor ev() { return ev; }
    void putEv(EvalVisitor e) { ev = e; }

    /** Evaluates this suspension. */
    public JamVal eval() { return exp.accept(ev); }

    public String toString() { return "<" + exp + ", " + ev + ">"; }
  }

  /** Class for a lazy cons with call-by-need optimization. */
  static class JamLazyNeedCons extends JamCons {
    private Suspension firstSusp;
    private Suspension restSusp;

    public JamLazyNeedCons(AST f, AST r, EvalVisitor ev) {
      super(null, null);
      firstSusp = new ConcreteSuspension(f, ev);
      restSusp = new ConcreteSuspension(r, ev);
    }

    public JamVal first() {
      if (first == null) {
        first = firstSusp.eval();
        firstSusp = null;
      }
      return first;
    }

    public JamList rest() {
      if (rest == null) {
        rest = checkList(restSusp.eval());
        restSusp = null;
      }
      return (JamList) rest;
    }
  }

  /** Eager cons evaluation policy. */
  public static final ConsPolicy EAGER = new ConsPolicy() {
    public JamVal evalCons(AST[] args, EvalVisitor ev) {
      JamVal val0 = args[0].accept(ev);
      JamVal val1 = args[1].accept(ev);
      if (val1 instanceof JamList) {
        return new JamCons(val0, (JamList) val1);
      }
      throw new EvalException("Second argument " + val1 + " to `cons' is not a JamList");
    }
  };

  /** Call-by-need lazy cons evaluation policy. */
  public static final ConsPolicy LAZYNEED = new ConsPolicy() {
    public JamVal evalCons(AST[] args, EvalVisitor ev) { return new JamLazyNeedCons(args[0], args[1], ev); }
  };

  /** Value-value visitor (call-by-value binding, eager cons). */
  static final ASTVisitor<JamVal> valueValueVisitor = new EvalVisitor(CALL_BY_VALUE, EAGER);

  /** Value-need visitor (call-by-value binding, lazy-need cons). */
  static final ASTVisitor<JamVal> valueNeedVisitor = new EvalVisitor(CALL_BY_VALUE, LAZYNEED);


  /** Primary visitor class for performing interpretation. */
  static class EvalVisitor implements ASTVisitor<JamVal> {

    /* Assumes that:
     *   OpTokens are unique
     *   Variable objects are unique: v1.name.equals(v.name) => v1 == v2
     *   Only objects used as boolean values are BoolConstant.TRUE and BoolConstant.FALSE
     * Hence, == can be used to compare Variable objects, OpTokens, and BoolConstants
     */

    /** Environment. */
    PureList<Binding> env;

    /** Policy to create bindings. */
    BindingPolicy bindingPolicy;

    /** Policy to create cons. */
    ConsPolicy consPolicy;

    private EvalVisitor(PureList<Binding> e, BindingPolicy bp, ConsPolicy cp) {
      env = e;
      bindingPolicy = bp;
      consPolicy = cp;
    }

    public EvalVisitor(BindingPolicy bp, ConsPolicy cp) { this(new Empty<Binding>(), bp, cp); }

    /* EvalVisitor methods */

    /** Factory method that constructs a visitor similar to this with environment env. */
    public EvalVisitor newEvalVisitor(PureList<Binding> env) {
      return new EvalVisitor(env, bindingPolicy, consPolicy);
    }

    /** Getter for env field. */
    public PureList<Binding> env() { return env; }

    /* methods of ASTVisitor<JamVal> interface */

    public JamVal forBoolConstant(BoolConstant b) { return b; }
    public JamVal forIntConstant(IntConstant i) { return i; }
    public JamVal forEmptyConstant(EmptyConstant n) { return JamEmpty.ONLY; }

    public JamVal forVariable(Variable v) {
      Binding match = env.accept(new LookupVisitor<Binding>(v));
      if (match == null) {
        throw new EvalException("variable " + v + " is unbound");
      }
      return match.value();
    }

    public JamVal forPrimFun(PrimFun f) { return f; }
    public JamVal forUnOpApp(UnOpApp u) { return u.rator().accept(new UnOpEvaluator(u.arg().accept(this))); }
    public JamVal forBinOpApp(BinOpApp b) { return b.rator().accept(new BinOpEvaluator(b.arg1(), b.arg2())); }

    public JamVal forApp(App a) {
      JamVal rator = a.rator().accept(this);
      if (rator instanceof JamFun)
        return ((JamFun) rator).accept(new FunEvaluator(a.args()));
      throw new EvalException(rator + " appears at head of application " + a + " but it is not a valid function");
    }

    public JamVal forMap(Map m) { return new JamClosure(m, env); }

    public JamVal forIf(If i) {
      JamVal test = i.test().accept(this);
      if (!(test instanceof BoolConstant)) throw new EvalException("non Boolean " + test + " used as test in if");
      if (test == BoolConstant.TRUE) return i.conseq().accept(this);
      return i.alt().accept(this);
    }

    /** Evaluates a block by evaluating all expressions in sequence, returning the last value. */
    public JamVal forBlock(Block b) {
      AST[] exps = b.exps();
      int n = exps.length;
      if (n == 0) throw new EvalException("Block must contain at least one expression");
      JamVal result = null;
      for (int i = 0; i < n; i++) {
        result = exps[i].accept(this);
      }
      return result;
    }

    /* Recursive let semantics */
    public JamVal forLet(Let l) {
      Variable[] vars = l.vars();
      AST[] exps = l.exps();
      int n = vars.length;

      /* Construct newEnv with dummy bindings for each variable in vars. */
      PureList<Binding> newEnv = env();
      Binding[] bindings = new Binding[n];
      for (int i = 0; i < n; i++) {
        bindings[i] = bindingPolicy.newDummyBinding(vars[i]);
        newEnv = newEnv.cons(bindings[i]);
      }
      EvalVisitor newEV = newEvalVisitor(newEnv);

      /* Fix up the dummy bindings in newEnv using exps as specified by binding policy */
      for (int i = 0; i < n; i++) {
        bindings[i].setBinding(new ConcreteSuspension(exps[i], newEV));
      }
      return l.body().accept(newEV);
    }

    /* Inner classes */

    /** Evaluates the application of a function to an array of argument ASTs. */
    class FunEvaluator implements JamFunVisitor<JamVal> {
      /** Unevaluated arguments */
      AST[] args;

      FunEvaluator(AST[] asts) { args = asts; }

      PrimFunVisitor<JamVal> primEvaluator = new PrimFunVisitor<JamVal>() {

        private JamVal[] evalArgs() {
          int n = args.length;
          JamVal[] vals = new JamVal[n];
          for (int i = 0; i < n; i++) {
            vals[i] = args[i].accept(EvalVisitor.this);
          }
          return vals;
        }

        private void primFunError(String fn) {
          throw new EvalException("Primitive function `" + fn + "' applied to " + args.length + " arguments");
        }

        private JamCons evalJamConsArg(AST arg, String fun) {
          JamVal val = arg.accept(EvalVisitor.this);
          if (val instanceof JamCons) {
            return (JamCons) val;
          }
          throw new EvalException("Primitive function `" + fun + "' applied to argument " + val + " that is not a JamCons");
        }

        public JamVal forFunctionPPrim() {
          JamVal[] vals = evalArgs();
          if (vals.length != 1) primFunError("function?");
          return BoolConstant.toBoolConstant(vals[0] instanceof JamFun);
        }

        public JamVal forNumberPPrim() {
          JamVal[] vals = evalArgs();
          if (vals.length != 1) primFunError("number?");
          return BoolConstant.toBoolConstant(vals[0] instanceof IntConstant);
        }

        public JamVal forListPPrim() {
          JamVal[] vals = evalArgs();
          if (vals.length != 1) primFunError("list?");
          return BoolConstant.toBoolConstant(vals[0] instanceof JamList);
        }

        public JamVal forConsPPrim() {
          JamVal[] vals = evalArgs();
          if (vals.length != 1) primFunError("cons?");
          return BoolConstant.toBoolConstant(vals[0] instanceof JamCons);
        }

        public JamVal forEmptyPPrim() {
          JamVal[] vals = evalArgs();
          if (vals.length != 1) primFunError("null?");
          return BoolConstant.toBoolConstant(vals[0] instanceof JamEmpty);
        }

        public JamVal forRefPPrim() {
          JamVal[] vals = evalArgs();
          if (vals.length != 1) primFunError("ref?");
          return BoolConstant.toBoolConstant(vals[0] instanceof JamRef);
        }

        public JamVal forConsPrim() {
          if (args.length != 2) primFunError("cons");
          return consPolicy.evalCons(args, EvalVisitor.this);
        }

        public JamVal forArityPrim() {
          JamVal[] vals = evalArgs();
          if (vals.length != 1) primFunError("arity");
          if (!(vals[0] instanceof JamFun)) throw new EvalException("arity applied to argument " + vals[0]);
          return ((JamFun) vals[0]).accept(new JamFunVisitor<IntConstant>() {
            public IntConstant forJamClosure(JamClosure jc) { return new IntConstant(jc.code().vars().length); }
            public IntConstant forPrimFun(PrimFun jpf) { return new IntConstant(jpf instanceof ConsPrim ? 2 : 1); }
          });
        }

        public JamVal forFirstPrim() {
          if (args.length != 1) primFunError("first");
          return evalJamConsArg(args[0], "first").first();
        }

        public JamVal forRestPrim() {
          if (args.length != 1) primFunError("rest");
          return evalJamConsArg(args[0], "rest").rest();
        }
      };  // end of anonymous inner class primEvaluator

      /* Support for JamFunVisitor<JamVal> interface */

      public JamVal forJamClosure(JamClosure closure) {
        Map map = closure.code();
        int n = args.length;
        Variable[] vars = map.vars();
        if (vars.length != n) {
          throw new EvalException("closure " + closure + " applied to " + n + " arguments");
        }
        PureList<Binding> newEnv = closure.env();
        for (int i = 0; i < n; i++) {
          newEnv = newEnv.cons(bindingPolicy.newBinding(vars[i], args[i], EvalVisitor.this));
        }
        return map.body().accept(newEvalVisitor(newEnv));
      }

      public JamVal forPrimFun(PrimFun primFun) { return primFun.accept(primEvaluator); }
    }

    /** Evaluator for unary operators. Operand is already a value (JamVal). */
    static class UnOpEvaluator implements UnOpVisitor<JamVal> {
      private JamVal val;

      UnOpEvaluator(JamVal jv) { val = jv; }

      private IntConstant checkInteger(String op) {
        if (val instanceof IntConstant) return (IntConstant) val;
        throw new EvalException("Unary operator `" + op + "' applied to non-integer " + val);
      }

      private BoolConstant checkBoolean(String op) {
        if (val instanceof BoolConstant) return (BoolConstant) val;
        throw new EvalException("Unary operator `" + op + "' applied to non-boolean " + val);
      }

      private JamRef checkRef(String op) {
        if (val instanceof JamRef) return (JamRef) val;
        throw new EvalException("Unary operator `" + op + "' applied to non-ref " + val);
      }

      public JamVal forUnOpPlus() { return checkInteger("+"); }
      public JamVal forUnOpMinus() { return new IntConstant(-checkInteger("-").value()); }
      public JamVal forOpTilde() { return checkBoolean("~").not(); }
      public JamVal forOpBang() { return checkRef("!").value(); }
      public JamVal forOpRef() { return new JamRef(val); }
    }

    /** Evaluator for binary operators. A true inner class that references the enclosing EvalVisitor. */
    class BinOpEvaluator implements BinOpVisitor<JamVal> {
      private AST arg1, arg2;

      BinOpEvaluator(AST a1, AST a2) {
        arg1 = a1;
        arg2 = a2;
      }

      private IntConstant evalIntegerArg(AST arg, String b) {
        JamVal val = arg.accept(EvalVisitor.this);
        if (val instanceof IntConstant) return (IntConstant) val;
        throw new EvalException("Binary operator `" + b + "' applied to non-integer " + val);
      }

      private BoolConstant evalBooleanArg(AST arg, String b) {
        JamVal val = arg.accept(EvalVisitor.this);
        if (val instanceof BoolConstant) return (BoolConstant) val;
        throw new EvalException("Binary operator `" + b + "' applied to non-boolean " + val);
      }

      public JamVal forBinOpPlus() {
        return new IntConstant(evalIntegerArg(arg1, "+").value() + evalIntegerArg(arg2, "+").value());
      }

      public JamVal forBinOpMinus() {
        return new IntConstant(evalIntegerArg(arg1, "-").value() - evalIntegerArg(arg2, "-").value());
      }

      public JamVal forOpTimes() {
        return new IntConstant(evalIntegerArg(arg1, "*").value() * evalIntegerArg(arg2, "*").value());
      }

      public JamVal forOpDivide() {
        int divisor = evalIntegerArg(arg2, "/").value();
        if (divisor == 0) {
          throw new EvalException("Attempt to divide by zero");
        }
        return new IntConstant(evalIntegerArg(arg1, "/").value() / divisor);
      }

      public JamVal forOpEquals() {
        return BoolConstant.toBoolConstant(arg1.accept(EvalVisitor.this).equals(arg2.accept(EvalVisitor.this)));
      }

      public JamVal forOpNotEquals() {
        return BoolConstant.toBoolConstant(!arg1.accept(EvalVisitor.this).equals(arg2.accept(EvalVisitor.this)));
      }

      public JamVal forOpLessThan() {
        return BoolConstant.toBoolConstant(evalIntegerArg(arg1, "<").value() < evalIntegerArg(arg2, "<").value());
      }

      public JamVal forOpGreaterThan() {
        return BoolConstant.toBoolConstant(evalIntegerArg(arg1, ">").value() > evalIntegerArg(arg2, ">").value());
      }

      public JamVal forOpLessThanEquals() {
        return BoolConstant.toBoolConstant(evalIntegerArg(arg1, "<=").value() <= evalIntegerArg(arg2, "<=").value());
      }

      public JamVal forOpGreaterThanEquals() {
        return BoolConstant.toBoolConstant(evalIntegerArg(arg1, ">=").value() >= evalIntegerArg(arg2, ">=").value());
      }

      public JamVal forOpAnd() {
        BoolConstant b1 = evalBooleanArg(arg1, "&");
        if (b1 == BoolConstant.FALSE) return BoolConstant.FALSE;
        return evalBooleanArg(arg2, "&");
      }

      public JamVal forOpOr() {
        BoolConstant b1 = evalBooleanArg(arg1, "|");
        if (b1 == BoolConstant.TRUE) return BoolConstant.TRUE;
        return evalBooleanArg(arg2, "|");
      }

      public JamVal forOpGets() {
        JamVal val1 = arg1.accept(EvalVisitor.this);
        if (!(val1 instanceof JamRef))
          throw new EvalException("Binary operator `<-' applied to non-ref " + val1);
        JamVal val2 = arg2.accept(EvalVisitor.this);
        ((JamRef) val1).setValue(val2);
        return JamUnit.ONLY;
      }
    } // end of BinOpEvaluator class
  } // end of EvalVisitor class
} // end of Interpreter class

/* The file defining the AST classes including the visitor interface, except for AST classes that are Token classes
 * as well. */

/** AST ::= BoolConstant | IntConstant | EmptyConstant | TypedEmptyConstant | Variable | PrimFun | UnOpApp | BinOpApp | App | Map | If | Let | Block */

/** AST class definitions */

/** The AST type which support a visitor interface */
interface AST {
  public <ResType> ResType accept(ASTVisitor<ResType> v);
}

interface ASTVisitor<ResType> {
  ResType forBoolConstant(BoolConstant b);
  ResType forIntConstant(IntConstant i);
  ResType forEmptyConstant(EmptyConstant n);
  /** Default handler for typed empty constants; delegates to forEmptyConstant by default. */
  default ResType forTypedEmptyConstant(TypedEmptyConstant n) { return forEmptyConstant(EmptyConstant.ONLY); }
  ResType forVariable(Variable v);
  ResType forPrimFun(PrimFun f);
  ResType forUnOpApp(UnOpApp u);
  ResType forBinOpApp(BinOpApp b);
  ResType forApp(App a);
  ResType forMap(Map m);
  ResType forIf(If i);
  ResType forLet(Let l);
  ResType forBlock(Block b);
}

/* The Term interface correspond to AST's that when output as concrete syntax by toString() can be used as terms
 * in an iterative binary expression without enclosing parentheses. We enclose all binary expressions in parentheses
 * so we do not presume either left or right associativity for infix binary operators. */
/** Term ::= Constant | PrimFun | Variable | UnOpApp |  App */
interface Term extends AST {}

/* NOTE: all Constant objects belong to the types Token and AST; Constant tokens evaluate to themselves.
 * The variant classes (IntConstant, BoolConstant, EmptyConstant) are defined in the file ValuesTokens.java */

/** Constant ::= IntConstant | BoolConstant | EmptyConstant */
interface Constant extends Term {}

/** UnOp ::= UnOpPlus | UnOpMinus | OpTilde */
/** Class representing the unary operator within a UnOppApp. */
abstract class UnOp {
  String name;
  public UnOp(String s) { name = s; }
  public String toString() { return name; }
  public abstract <ResType> ResType accept(UnOpVisitor<ResType> v);
}

/** Visitor for the UnOp union type. */
interface UnOpVisitor<ResType> {
  ResType forUnOpPlus();
  ResType forUnOpMinus();
  ResType forOpTilde();
  ResType forOpBang();
  ResType forOpRef();
}

/** BinOp ::= BinOpPlus | BinOpMinus | OpTimes | OpDivide | OpEquals | OpNotEquals | OpLessThan | OpGreaterThan |
  *           OpLessThanOrEquals OpGreaterThanOrEquals | OpAnd | OpOr */

/** Class representing the binary operator within a BinOppApp. */
abstract class BinOp {
  String name;
  public BinOp(String s) { name = s; }
  public String toString() { return name; }
  public abstract <ResType> ResType accept(BinOpVisitor<ResType> v);
}

/** Visitor for the BinOp union type. */
interface BinOpVisitor<ResType> {
  ResType forBinOpPlus();
  ResType forBinOpMinus();
  ResType forOpTimes();
  ResType forOpDivide();
  ResType forOpEquals();
  ResType forOpNotEquals();
  ResType forOpLessThan();
  ResType forOpGreaterThan();
  ResType forOpLessThanEquals();
  ResType forOpGreaterThanEquals();
  ResType forOpAnd();
  ResType forOpOr();
  ResType forOpGets();
}

