/** Parser for Assignment 5: Typed Jam */

import java.io.*;
import java.util.*;

/** Class that represented parsing errors. */
class ParseException extends RuntimeException {
  ParseException(String s) { super(s); }
  ParseException(Throwable t) { super(t); }
}

class Parser {

  private Lexer in;

  Parser(Lexer i) { in = i; }

  Parser(Reader inputStream) { this(new Lexer(inputStream)); }

  Parser(String fileName) throws IOException { this(new FileReader(fileName)); }

  Lexer lexer() { return in; }

  public void initParser() { }

  /** Parses the program in the Lexer associated with this. */
  public AST parse() throws ParseException {
    try {
      in.reset();
      AST prog = parseExp();
      Token t = in.readToken();
      if (t == EndOfFile.ONLY) return prog;
      else throw new ParseException("Legal program followed by extra token " + t);
    }
    finally {
      try { in.rdr.close(); }
      catch (IOException e) { throw new ParseException(e); }
    }
  }

  /** Parses and syntactically checks the program in the Lexer associated with this. */
  public AST parseAndCheck() throws ParseException {
    AST prog = parseExp();
    Token t = in.readToken();
    if (t != EndOfFile.ONLY) throw new ParseException("Legal program '" + prog + "' followed by extra token " + t);

    /* Invoke the CheckVisitor to confirm prog does not contain free variables or duplicate parameter names. */
    prog.accept(CheckVisitor.INITIAL);   // aborts on an error by throwing an exception
    return prog;
  }

  /** Parses:
    *   <exp> ::= if <exp> then <exp> else <exp>
    *           | let <prop-def-list> in <exp>
    *           | map <typed-id-list> to <exp>
    *           | { <exp-list> }    (block)
    *           | <term> { <binop> <term> }*
    */
  private AST parseExp() {
    Token token = in.readToken();

    if (token == Lexer.IF) return parseIf();
    if (token == Lexer.LET) return parseLet();
    if (token == Lexer.MAP) return parseMap();

    /* Supports the addition of blocks to Jam */
    if (token == LeftBrace.ONLY) {
      AST[] exps = parseExps(SemiColon.ONLY, RightBrace.ONLY);
      if (exps.length == 0) throw new ParseException("Illegal empty block");
      return new Block(exps);
    }

    /* phrase begins with a term */
    AST exp = parseTerm(token);

    Token next = in.peek();
    while (next instanceof OpToken) {
      OpToken op = (OpToken) next;
      in.readToken(); // remove next from input stream
      if (! (op.isBinOp())) error(next, "binary operator");
      AST newTerm = parseTerm(in.readToken());
      exp = new BinOpApp(op.toBinOp(), exp, newTerm);
      next = in.peek();
    }
    return exp;
  }

  /** Parses a term according to the typed Jam grammar:
    *   <term> ::= <unop> <term>
    *            | <prim> ( <exp-list> )
    *            | empty : <type>
    *            | <int-constant>
    *            | <bool-constant>
    *            | <factor> { ( <exp-list> ) }
    *
    * Removed primitives (list?, number?, function?, ref?, arity) cause a parse error.
    * @param token  first token in input stream to be parsed; remainder in Lexer named in.
    */
  private AST parseTerm(Token token) {

    /* Handle unary operators */
    if (token instanceof OpToken) {
      OpToken op = (OpToken) token;
      if (! op.isUnOp()) error(op, "unary operator");
      return new UnOpApp(op.toUnOp(), parseTerm(in.readToken()));
    }

    /* Handle 'empty : Type' */
    if (token == EmptyConstant.ONLY) {
      Token colon = in.readToken();
      if (colon != Lexer.COLON) error(colon, "`:'");
      JamType elemType = parseType();
      return new TypedEmptyConstant(elemType);
    }

    /* Handle integer and boolean constants */
    if (token instanceof IntConstant || token instanceof BoolConstant) {
      return (Constant) token;
    }

    /* Handle Prim: must be followed by ( ExpList ) */
    if (token instanceof PrimFun) {
      PrimFun prim = (PrimFun) token;
      /* Reject removed primitives */
      if (prim instanceof FunctionPPrim || prim instanceof NumberPPrim ||
          prim instanceof ListPPrim || prim instanceof RefPPrim || prim instanceof ArityPrim) {
        error(token, "a valid primitive (list?, number?, function?, ref?, arity are not in typed Jam)");
      }
      Token lp = in.readToken();
      if (lp != LeftParen.ONLY) error(lp, "`('");
      AST[] exps = parseArgs();
      return new App(prim, exps);
    }

    /* Handle Factor { ( ExpList ) } */
    AST factor = parseFactor(token);
    Token next = in.peek();
    if (next == LeftParen.ONLY) {
      in.readToken();  // consume '('
      AST[] exps = parseArgs();
      return new App(factor, exps);
    }
    return factor;
  }

  /** Parses: <factor> ::= ( <exp> ) | <id>
    * In typed Jam, factors are only identifiers or parenthesized expressions.
    * @param token  first token in input stream to be parsed; remainder in Lexer named in.
    */
  private AST parseFactor(Token token) {
    if (token == LeftParen.ONLY) {
      AST exp = parseExp();
      token = in.readToken();
      if (token != RightParen.ONLY) error(token, "`)'");
      return exp;
    }

    if (! (token instanceof Variable))
      error(token, "variable or `('");

    return (Variable) token;
  }

  /** Parses `if <exp> then <exp> else <exp>' given that `if' has already been read. */
  private AST parseIf() {
    AST test = parseExp();
    Token key1 = in.readToken();
    if (key1 != Lexer.THEN) error(key1, "`then'");
    AST conseq = parseExp();
    Token key2 = in.readToken();
    if (key2 != Lexer.ELSE) error(key2, "`else'");
    AST alt = parseExp();
    return new If(test, conseq, alt);
  }

  /** Parses `let <prop-def-list> in <exp>' given that `let' has already been read. */
  private AST parseLet() {
    Def[] defs = parseDefs(false);
    AST body = parseExp();
    return new Let(defs, body);
  }

  /** Parses `map <typed-id-list> to <exp>' given that `map' has already been read. */
  private AST parseMap() {
    TypedVariable[] typedVars = parseTypedVars();
    Variable[] vars = new Variable[typedVars.length];
    JamType[] types = new JamType[typedVars.length];
    for (int i = 0; i < typedVars.length; i++) {
      vars[i] = typedVars[i].var();
      types[i] = typedVars[i].type();
    }
    AST body = parseExp();
    return new Map(vars, types, body);
  }

  /** Parses `<exp-list> <delim>' where
    *  <exp-list>      ::= <empty> | <prop-exp-list>
    *  <prop-exp-list> ::= <exp> | <exp> <separator> <prop-exp-list>
    */
  private AST[] parseExps(Token separator, Token delim) {
    LinkedList<AST> exps = new LinkedList<AST>();
    Token next = in.peek();

    if (next == delim) {
      in.readToken(); // consume delim
      return new AST[0];
    }

    do {
      AST exp = parseExp();
      exps.addLast(exp);
      next = in.readToken();
    } while (next == separator);

    if (next != delim) error(next, "`,' or `)'");
    return (AST[]) exps.toArray(new AST[0]);
  }

  private AST[] parseArgs() { return parseExps(Comma.ONLY, RightParen.ONLY); }

  /** Parses a typed-id-list: { <typed-id> , ... } followed by 'to'.
    *   <typed-id-list>      ::= { <prop-typed-id-list> }
    *   <prop-typed-id-list> ::= <typed-id> | <typed-id> , <prop-typed-id-list>
    *   <typed-id>           ::= <id> : <type>
    * NOTE: consumes 'to' following the list.
    */
  private TypedVariable[] parseTypedVars() {
    LinkedList<TypedVariable> vars = new LinkedList<TypedVariable>();
    Token t = in.readToken();

    /* Empty parameter list: map to exp */
    if (t == Lexer.TO) return new TypedVariable[0];

    do {
      if (!(t instanceof Variable)) error(t, "variable");
      Variable v = (Variable) t;
      Token colon = in.readToken();
      if (colon != Lexer.COLON) error(colon, "`:'");
      JamType type = parseType();
      vars.addLast(new TypedVariable(v, type));
      t = in.readToken();
      if (t == Lexer.TO) break;
      if (t != Comma.ONLY) error(t, "`to' or `, '");
      t = in.readToken();
    } while (true);

    return (TypedVariable[]) vars.toArray(new TypedVariable[0]);
  }

  /** Parses a proper list of definitions:
    *   <prop-def-list> ::= <def> | <def> <def-list>
    *   NOTE: consumes 'in' following <prop-def-list>
    */
  private Def[] parseDefs(boolean forceMap) {
    LinkedList<Def> defs = new LinkedList<Def>();
    Token t = in.readToken();

    do {
      Def d = parseDef(t);
      if (forceMap && (! (d.rhs() instanceof Map)))
        throw new ParseException("right hand side of definition `" + d + "' is not a map expression");
      defs.addLast(d);
      t = in.readToken();
    } while (t != Lexer.IN);

    return (Def[]) defs.toArray(new Def[0]);
  }

  /** Parses <id> : <type> := <exp> ; which is <def> given that first token var has been read. */
  private Def parseDef(Token var) {
    if (!(var instanceof Variable)) error(var, "variable");

    Token colon = in.readToken();
    if (colon != Lexer.COLON) error(colon, "`:'");

    JamType type = parseType();

    Token key = in.readToken();
    if (key != Lexer.BIND) error(key, "`:='");

    AST exp = parseExp();

    Token semi = in.readToken();
    if (semi != SemiColon.ONLY) error(semi, "`; '");

    return new Def((Variable) var, type, exp);
  }

  /** Parses a type according to:
    *   <type> ::= unit | int | bool | list <type> | ref <type> | ( <type-list> -> <type> )
    */
  private JamType parseType() {
    Token t = in.readToken();

    if (t instanceof Variable) {
      String name = ((Variable) t).name();
      if (name.equals("int"))  return IntType.ONLY;
      if (name.equals("bool")) return BoolType.ONLY;
      if (name.equals("unit")) return UnitType.ONLY;
      if (name.equals("list")) {
        JamType elem = parseType();
        return new ListType(elem);
      }
      error(t, "type name (int, bool, unit, or list)");
    }

    /* 'ref' is an OpToken (Lexer.REF) in the wordTable */
    if (t == Lexer.REF) {
      JamType elem = parseType();
      return new RefType(elem);
    }

    /* ( TypeList -> Type ) */
    if (t == LeftParen.ONLY) {
      return parseFunType();
    }

    error(t, "type");
    return null; // unreachable
  }

  /** Parses ( <type-list> -> <type> ) given that '(' has already been consumed.
    *   <type-list>      ::= { <prop-type-list> }
    *   <prop-type-list> ::= <type> | <type> , <prop-type-list>
    */
  private FunType parseFunType() {
    Token next = in.peek();

    /* Empty parameter list: ( -> Type ) */
    if (next == Lexer.MINUS) {
      in.readToken();  // consume '-'
      Token gt = in.readToken();
      if (gt != Lexer.GREATER_THAN) error(gt, "`>' (part of `->') after `-'");
      JamType result = parseType();
      Token rp = in.readToken();
      if (rp != RightParen.ONLY) error(rp, "`)'");
      return new FunType(new JamType[0], result);
    }

    /* Non-empty parameter list */
    LinkedList<JamType> paramTypes = new LinkedList<JamType>();
    while (true) {
      JamType paramType = parseType();
      paramTypes.addLast(paramType);
      Token sep = in.readToken();
      if (sep == Comma.ONLY) {
        continue;
      }
      if (sep == Lexer.MINUS) {
        Token gt = in.readToken();
        if (gt != Lexer.GREATER_THAN) error(gt, "`>' (part of `->') after `-'");
        break;
      }
      error(sep, "`,', or `->'");
    }

    JamType result = parseType();
    Token rp = in.readToken();
    if (rp != RightParen.ONLY) error(rp, "`)'");
    return new FunType(paramTypes.toArray(new JamType[0]), result);
  }

  private AST error(Token found, String expected) {
    throw new ParseException("Token `" + found + "' appears where " + expected + " was expected");
  }

  /** A legacy "main" method. */
  public static void main(String[] args) throws IOException {
    if (args.length == 0) return;
    Parser p = new Parser(args[0]);
    AST prog = p.parse();
  }
}

/** Jam lexer class for all assignments.              
  * Given a Lexer object, the next token in that input stream being processed by the Lexer is returned by the
  * readToken() method; it throws a ParseException (a form of RuntimeException) if it encounters a syntax error.  
  * Calling readToken() advances the cursor in the input stream to the next token.
  * 
  * The method peek() in the Lexer class has the same behavior as readToken() except for the fact that it does not
  * advance the cursor.
  */

import java.io.BufferedReader;
import java.io.FileReader;
import java.io.InputStreamReader;
import java.io.IOException;
import java.io.Reader;
import java.io.StreamTokenizer;
import java.util.HashMap;

class Lexer extends StreamTokenizer {

  /* short names for StreamTokenizer codes */

  public static final int WORD = StreamTokenizer.TT_WORD; 
  public static final int NUMBER = StreamTokenizer.TT_NUMBER; 
  public static final int EOF = StreamTokenizer.TT_EOF; 
  public static final int EOL = StreamTokenizer.TT_EOL; 

  /* operator Tokens */

  // <unop>  ::= <sign> | ~   | ! 
  // <binop> ::= <sign> | "*" | / | = | != | < | > | <= | >= | & | "|" | <- 
  // <sign>  ::= "+" | -

  //  Note: there is no class distinction between <unop> and <binop> at 
  //  lexical level because of ambiguity; <sign> belongs to both

  public static final OpToken PLUS = OpToken.newBothOpToken(UnOpPlus.ONLY, BinOpPlus.ONLY); 
  public static final OpToken MINUS = OpToken.newBothOpToken(UnOpMinus.ONLY, BinOpMinus.ONLY);
  public static final OpToken TIMES = OpToken.newBinOpToken(OpTimes.ONLY);
  public static final OpToken DIVIDE = OpToken.newBinOpToken(OpDivide.ONLY);
  public static final OpToken EQUALS = OpToken.newBinOpToken(OpEquals.ONLY);
  public static final OpToken NOT_EQUALS = OpToken.newBinOpToken(OpNotEquals.ONLY);
  public static final OpToken LESS_THAN = OpToken.newBinOpToken(OpLessThan.ONLY);
  public static final OpToken GREATER_THAN = OpToken.newBinOpToken(OpGreaterThan.ONLY);
  public static final OpToken LESS_THAN_EQUALS = OpToken.newBinOpToken(OpLessThanEquals.ONLY);
  public static final OpToken GREATER_THAN_EQUALS = OpToken.newBinOpToken(OpGreaterThanEquals.ONLY);
  public static final OpToken NOT = OpToken.newUnOpToken(OpTilde.ONLY);
  public static final OpToken AND = OpToken.newBinOpToken(OpAnd.ONLY);
  public static final OpToken OR = OpToken.newBinOpToken(OpOr.ONLY);

  /* Used to support reference cells. */
  public static final OpToken BANG = OpToken.newUnOpToken(OpBang.ONLY);
  public static final OpToken GETS = OpToken.newBinOpToken(OpGets.ONLY);
  public static final OpToken REF = OpToken.newUnOpToken(OpRef.ONLY);

  /* Used to support typed Jam syntax: ':' alone is a valid token */
  public static final KeyWord COLON = new KeyWord(":");

  /* Keywords */

  public static final KeyWord IF     = new KeyWord("if");
  public static final KeyWord THEN   = new KeyWord("then");
  public static final KeyWord ELSE   = new KeyWord("else");
  public static final KeyWord LET    = new KeyWord("let");
//  public static final KeyWord LETREC = new KeyWord("letrec");   // Used to support separate letrec construction
  public static final KeyWord IN     = new KeyWord("in");
  public static final KeyWord MAP    = new KeyWord("map");
  public static final KeyWord TO     = new KeyWord("to");
  public static final KeyWord BIND   = new KeyWord(":=");

  /* fields */

  /** The Reader from which this lexer reads. */
  public final Reader rdr;

  /* The wordtable for classifying words in token stream */
  public HashMap<String,Token>  wordTable = new HashMap<String,Token>();

  /** The buffer holding the next token in the intput stream; it is used to support the peek() operation, which cannot
    * be implemented using StreamTokenizer pushBack because some Tokens are composed of two StreamTokenizer tokens. */
  Token buffer;

  /* constructors */

  /** Constructs a Lexer for the specified inputStream */
  Lexer(Reader inputStream) {
    super(new BufferedReader(inputStream));
    rdr = inputStream;
    initLexer();
  }

  /** Constructor that uses a File as the input stream. */
  Lexer(String fileName) throws IOException {
    this(new FileReader(fileName));
  }

  /* Initializes lexer tables and the StreamTokenizer that the lexer extends */
  private void initLexer() {

    // configure StreamTokenizer portion of this
    resetSyntax();
    parseNumbers();
    ordinaryChar('-');
    slashSlashComments(true);
    wordChars('0', '9');
    wordChars('a', 'z');
    wordChars('A', 'Z');
    wordChars('_', '_');
    wordChars('?', '?');
    whitespaceChars(0, ' '); 

    // `+' `-' `*' `/' `~' `=' `<' `>' `&' `|' `:' `;' `,' '!'
    // `(' `)' `[' `]' are ordinary characters (self-delimiting)

    initWordTable();
    buffer = null;  // buffer initially empty
  }

  /** Resets the reader embedded in this lexer.  The same file may be scanned multiple times in tests. */
  public void reset() throws ParseException { 
    try { rdr.reset(); }
    catch(IOException e) { throw new ParseException(e); }
  }

  /** Reads tokens until next end-of-line */
  public void flush() throws IOException {
    eolIsSignificant(true);
    while (nextToken() != EOL) ; // eat tokens until EOL
    eolIsSignificant(false);
  }

  /** Returns the next token in the input stream without consuming it */
  public Token peek() { 
    if (buffer == null) buffer = readToken();
    return buffer;
  }

  /** Reads the next token as defined by StreamTokenizer in the input stream (consuming it). */
  private int getToken() {
    // synonymous with nextToken() except for throwing an unchecked 
    // ParseException instead of a checked IOException
    try {
      int tokenType = nextToken();
      return tokenType;
    } catch(IOException e) {
      throw new ParseException("IOException " + e + "thrown by nextToken()");
    }
  }

  /** Reads the next Token in the input stream (consuming it) */
  public Token readToken() {

    /* Uses getToken() to read next token and constructs the Token object representing that token.
     * NOTE: token representations for all Token classes except IntConstant are unique; a HashMap 
     * is used to avoid duplication.  Hence, == can safely be used to compare all Tokens except 
     * IntConstants for equality (assuming that code does not gratuitously create Tokens).  When the
     * stream is reduced to EOT, returns null instead of a Token.
     */

    if (buffer != null) {
      Token token = buffer;
      buffer = null;          // clear buffer
      return token;
    }

    int tokenType = getToken();

    switch (tokenType) {

      case NUMBER:
        int value = (int) nval;
        if (nval == (double) value) return new IntConstant(value);
        throw new ParseException("The number " + nval + " is not a 32 bit integer");
      case WORD:
        Token regToken = wordTable.get(sval);
        if (regToken == null) {
          // must be new variable name
          Variable newVar = new Variable(sval);
          wordTable.put(sval, newVar);
          return newVar;
        }
        return regToken;

      case EOF: return EndOfFile.ONLY;
      case '(': return LeftParen.ONLY;
      case ')': return RightParen.ONLY;
      case '[': return LeftBrack.ONLY;
      case ']': return RightBrack.ONLY;
      case '{': return LeftBrace.ONLY;
      case '}': return RightBrace.ONLY;
      case ',': return Comma.ONLY;
      case ';': return SemiColon.ONLY;

      case '+': return PLUS;  
      case '-': return MINUS;  
      case '*': return TIMES;  
      case '/': return DIVIDE;  
      case '~': return NOT;  
      case '=': return EQUALS;

      case '<':
        tokenType = getToken();
        if (tokenType == '=') return LESS_THAN_EQUALS;
        if (tokenType == '-') return GETS;    // Used to support reference cells
        pushBack();
        return LESS_THAN; 

      case '>': 
        tokenType = getToken();
        if (tokenType == '=') return GREATER_THAN_EQUALS;  
        pushBack();
        return GREATER_THAN;

      case '!':
        tokenType = getToken();
        if (tokenType == '=') return NOT_EQUALS;
        pushBack();
        return BANG;  // Used to support reference cells 

      case '&': return AND;  
      case '|': return OR;  
      case ':': {
        tokenType = getToken();
        if (tokenType == '=') return BIND;   // ":=" is a keyword
        pushBack();
        return COLON;  // ':' alone is valid in typed Jam syntax
      }
      default:  
        throw new 
        ParseException("'" + ((char) tokenType) + "' is not a legal token");
    }
  }

  /** Initializes the table of Strings used to recognize Tokens */
  private void initWordTable() {
    // initialize wordTable

    // constants
    // <empty>  ::= empty
    // <bool>  ::= true | false

    wordTable.put("empty", EmptyConstant.ONLY);
    wordTable.put("true",  BoolConstant.TRUE);
    wordTable.put("false", BoolConstant.FALSE); 

    // Install primitive functions // (and unary operator named "ref" which is added in Assignment 4)
    // <prim>  ::= number? | function? | list? | empty? | cons? | ref? | arity | cons | first | rest 
    // Note: ref? is added in Assignment 4

    wordTable.put("number?",   NumberPPrim.ONLY);
    wordTable.put("function?", FunctionPPrim.ONLY);
    wordTable.put("list?",     ListPPrim.ONLY);
    wordTable.put("empty?",    EmptyPPrim.ONLY);
    wordTable.put("cons?",     ConsPPrim.ONLY);
    wordTable.put("ref?",      RefPPrim.ONLY);  // Supports the addition of reference cells
    wordTable.put("ref",       REF);            // Supports the addition of reference cells
    wordTable.put("arity",     ArityPrim.ONLY);  
    wordTable.put("cons",      ConsPrim.ONLY);
    wordTable.put("first",     FirstPrim.ONLY);
    wordTable.put("rest",      RestPrim.ONLY);


    // keywords: if then else let in map to := 
    wordTable.put("if",   Lexer.IF);
    wordTable.put("then", Lexer.THEN);
    wordTable.put("else", Lexer.ELSE);
    wordTable.put("let",  Lexer.LET);
    wordTable.put("in",   Lexer.IN);
    wordTable.put("map",  Lexer.MAP);
    wordTable.put("to",   Lexer.TO);    
  }
}

