+/* ===== Type Hierarchy for Typed Jam ===== */
+
+/** The interface representing Jam types. */
+interface JamType {}
+
+/** Represents the integer type 'int'. */
+class IntType implements JamType {
+  public static final IntType ONLY = new IntType();
+  private IntType() {}
+  public boolean equals(Object o) { return o instanceof IntType; }
+  public int hashCode() { return 1; }
+  public String toString() { return "int"; }
+}
+
+/** Represents the boolean type 'bool'. */
+class BoolType implements JamType {
+  public static final BoolType ONLY = new BoolType();
+  private BoolType() {}
+  public boolean equals(Object o) { return o instanceof BoolType; }
+  public int hashCode() { return 2; }
+  public String toString() { return "bool"; }
+}
+
+/** Represents the unit type 'unit'. */
+class UnitType implements JamType {
+  public static final UnitType ONLY = new UnitType();
+  private UnitType() {}
+  public boolean equals(Object o) { return o instanceof UnitType; }
+  public int hashCode() { return 3; }
+  public String toString() { return "unit"; }
+}
+
+/** Represents the list type 'list T' for element type T. */
+class ListType implements JamType {
+  private JamType elem;
+  ListType(JamType e) { elem = e; }
+  public JamType elem() { return elem; }
+  public boolean equals(Object o) {
+    return (o instanceof ListType) && ((ListType)o).elem.equals(elem);
+  }
+  public int hashCode() { return 4 + elem.hashCode(); }
+  public String toString() { return "list " + elem; }
+}
+
+/** Represents the reference type 'ref T' for element type T. */
+class RefType implements JamType {
+  private JamType elem;
+  RefType(JamType e) { elem = e; }
+  public JamType elem() { return elem; }
+  public boolean equals(Object o) {
+    return (o instanceof RefType) && ((RefType)o).elem.equals(elem);
+  }
+  public int hashCode() { return 5 + elem.hashCode(); }
+  public String toString() { return "ref " + elem; }
+}
+
+/** Represents the function type '(T1, T2, ... -> T)'. */
+class FunType implements JamType {
+  private JamType[] params;
+  private JamType result;
+  FunType(JamType[] p, JamType r) { params = p; result = r; }
+  public JamType[] params() { return params; }
+  public JamType result() { return result; }
+  public boolean equals(Object o) {
+    if (!(o instanceof FunType)) return false;
+    FunType other = (FunType) o;
+    if (params.length != other.params.length) return false;
+    for (int i = 0; i < params.length; i++) {
+      if (!params[i].equals(other.params[i])) return false;
+    }
+    return result.equals(other.result);
+  }
+  public int hashCode() {
+    int h = 6 + result.hashCode();
+    for (JamType p : params) h += p.hashCode();
+    return h;
+  }
+  public String toString() {
+    StringBuilder sb = new StringBuilder("(");
+    for (int i = 0; i < params.length; i++) {
+      if (i > 0) sb.append(", ");
+      sb.append(params[i]);
+    }
+    sb.append(" -> ");
+    sb.append(result);
+    sb.append(")");
+    return sb.toString();
+  }
+}
+
+/** A typed variable pairing an identifier with its declared type. Used during parsing. */
+class TypedVariable {
